-- Role for any profile on a project (owner from projects row wins).
create or replace function public.project_role_for_profile(p_project_id uuid, p_profile_id uuid)
returns text
language sql
stable
security definer
set search_path = public
as $$
  select case
    when exists (
      select 1
      from public.projects p
      where p.id = p_project_id
        and p.owner_profile_id = p_profile_id
    ) then 'owner'
    else (
      select pm.role
      from public.project_members pm
      where pm.project_id = p_project_id
        and pm.profile_id = p_profile_id
      limit 1
    )
  end
$$;

-- Maximum capability ranks an actor may delegate (from their stored member row or owner defaults).
create or replace function public.actor_ai_access_delegate_cap(p_project_id uuid, p_actor uuid)
returns integer
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_role text;
  v_ai text;
begin
  v_role := public.project_role_for_profile(p_project_id, p_actor);
  if v_role is null then
    return -1;
  end if;
  if v_role = 'owner' then
    return public.ai_access_rank('project_pool');
  end if;
  select pm.ai_access
  into v_ai
  from public.project_members pm
  where pm.project_id = p_project_id
    and pm.profile_id = p_actor;
  return coalesce(public.ai_access_rank(v_ai), -1);
end;
$$;

