-- Central delegation check: actor must be owner or co_owner; role and caps must not exceed actor's.
create or replace function public.assert_project_participant_delegate_ok(
  p_actor uuid,
  p_project_id uuid,
  p_role text,
  p_ai_access text,
  p_finance_visibility text,
  p_internal_docs_visibility text
)
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_actor_role text;
  v_ai_cap int;
  v_fin_cap int;
  v_doc_cap int;
begin
  if p_actor is null then
    raise exception 'Delegation check requires an actor';
  end if;

  v_actor_role := public.project_role_for_profile(p_project_id, p_actor);
  if v_actor_role is null then
    raise exception 'Actor is not a participant on this project';
  end if;

  if v_actor_role in ('viewer', 'contractor') then
    raise exception 'Insufficient authority to assign participants';
  end if;

  if p_role = 'owner' then
    raise exception 'Owner role cannot be assigned through invites or member grants';
  end if;

  if p_role = 'co_owner' and v_actor_role <> 'owner' then
    raise exception 'Only the project owner may create or promote co_owners';
  end if;

  if v_actor_role = 'co_owner' and p_role not in ('contractor', 'viewer') then
    raise exception 'Co-owners may only invite or assign contractor or viewer roles';
  end if;

  v_ai_cap := public.actor_ai_access_delegate_cap(p_project_id, p_actor);
  v_fin_cap := public.actor_finance_visibility_delegate_cap(p_project_id, p_actor);
  v_doc_cap := public.actor_internal_docs_delegate_cap(p_project_id, p_actor);

  if public.ai_access_rank(p_ai_access) > v_ai_cap then
    raise exception 'Cannot grant AI access above the actor''s own level';
  end if;

  if public.finance_visibility_rank(p_finance_visibility) > v_fin_cap then
    raise exception 'Cannot grant finance visibility above the actor''s own level';
  end if;

  if public.internal_docs_visibility_rank(p_internal_docs_visibility) > v_doc_cap then
    raise exception 'Cannot grant internal document access above the actor''s own level';
  end if;
end;
$$;

-- Effective values for the current user (stored row; owner without row uses max preset).
create or replace function public.effective_finance_visibility(p_project_id uuid)
returns text
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_fin text;
  v_role text;
begin
  if v_uid is null then
    return null;
  end if;
  v_role := public.project_role_for_profile(p_project_id, v_uid);
  if v_role is null then
    return null;
  end if;
  select pm.finance_visibility
  into v_fin
  from public.project_members pm
  where pm.project_id = p_project_id
    and pm.profile_id = v_uid;
  if v_fin is not null then
    return v_fin;
  end if;
  if v_role = 'owner' then
    return 'detail';
  end if;
  return 'none';
end;
$$;

